  public var resumeKey: String

  public init(wait: PolicyWaitCondition, resumeKey: String) {
    self.wait = wait
    self.resumeKey = resumeKey
  }

  enum CodingKeys: String, CodingKey {
    case wait
    case resumeKey = "resume_key"
  }
}

public enum PolicyWaitCondition: Codable, Equatable, Sendable {
  case timer(durationSeconds: UInt64)
  case event(eventKey: String)

  enum CodingKeys: String, CodingKey {
    case kind
    case durationSeconds = "duration_seconds"
    case eventKey = "event_key"
  }

  public init(from decoder: Decoder) throws {
    let container = try decoder.container(keyedBy: CodingKeys.self)
    let kind = try container.decode(String.self, forKey: .kind)
    switch kind {
    case "timer":
      self = .timer(durationSeconds: try container.decode(UInt64.self, forKey: .durationSeconds))
    case "event":
      self = .event(eventKey: try container.decode(String.self, forKey: .eventKey))
    default:
      throw DecodingError.dataCorruptedError(forKey: .kind, in: container, debugDescription: "unknown PolicyWaitCondition kind \(kind)")
    }
  }

  public func encode(to encoder: Encoder) throws {
    var container = encoder.container(keyedBy: CodingKeys.self)
    switch self {
    case .timer(let durationSeconds):
      try container.encode("timer", forKey: .kind)
      try container.encode(durationSeconds, forKey: .durationSeconds)
    case .event(let eventKey):
      try container.encode("event", forKey: .kind)
      try container.encode(eventKey, forKey: .eventKey)
    }
  }
}

